import React from 'react';
import { AsyncStorage } from 'react-native';
import CryptoJS from 'crypto-js';

// Config file for encryption key
export const ENCRYPTION_KEY = 'your-encryption-key-here';

// Encryption utility functions
const encrypt = (text, key) => {
  return CryptoJS.AES.encrypt(text, key).toString();
};

const decrypt = (encryptedText, key) => {
  const bytes = CryptoJS.AES.decrypt(encryptedText, key);
  return bytes.toString(CryptoJS.enc.Utf8);
};

// Async Storage functions with encryption
export const saveProfile = async (profile) => {
  try {
    const encryptedProfile = encrypt(JSON.stringify(profile), ENCRYPTION_KEY);
    await AsyncStorage.setItem('userProfile', encryptedProfile);
  } catch (error) {
    console.error('Error saving profile:', error);
  }
};

export const getProfile = async () => {
  try {
    const encryptedProfile = await AsyncStorage.getItem('userProfile');
    if (encryptedProfile !== null) {
      const decryptedProfile = decrypt(encryptedProfile, ENCRYPTION_KEY);
      return JSON.parse(decryptedProfile);
    }
    return null;
  } catch (error) {
    console.error('Error getting profile:', error);
    return null;
  }
};

